<div class="d-flex justify-content-between mb-2"><h1 class="h5">Planes</h1><a href="/admin/planes/crear" class="btn btn-primary btn-sm">Nuevo plan</a></div><div class="table-responsive"><table class="table table-sm"><thead><tr><th>Nombre</th><th>Slug</th><th>Mensual</th><th>Visible</th><th>Estado</th><th></th></tr></thead><tbody><?php foreach($planes as $plan): ?><tr><td><?= e($plan['nombre']) ?></td><td><?= e($plan['slug']) ?></td><td>$<?= number_format((float)$plan['precio_mensual'],2) ?></td><td><?= $plan['visible'] ? 'Sí' : 'No' ?></td><td><span class="badge text-bg-light"><?= e($plan['estado']) ?></span></td><td><a href="/admin/planes/editar/<?= $plan['id'] ?>" class="btn btn-outline-secondary btn-sm">Editar</a> <a href="/admin/plan-funcionalidades/<?= $plan['id'] ?>" class="btn btn-outline-primary btn-sm">Funcionalidades</a></td></tr><?php endforeach; ?></tbody></table></div>
